// Parse incoming data
const data = $input.all()[0].json;

// Parse CSV if string
let parsed = data;
if (typeof data.file === 'string') {
  const lines = data.file.split('\n').filter(l => l.trim());
  const headers = lines[0].split(',').map(h => h.trim().replace(/"/g, ''));
  const rows = lines.slice(1);

  parsed = {
    email: data.email,
    name: data.name,
    filename: data.filename,
    headers,
    rowCount: rows.length
  };
}

// Calculate stats
const stats = {};
parsed.headers?.forEach((header, i) => {
  const values = rows?.map(row => {
    const cols = row.split(',');
    return parseFloat(cols[i]?.trim());
  }).filter(v => !isNaN(v)) || [];

  if (values.length > 0) {
    stats[header] = {
      count: values.length,
      sum: parseFloat(values.reduce((a, b) => a + b, 0).toFixed(2)),
      avg: parseFloat((values.reduce((a, b) => a + b, 0) / values.length).toFixed(2)),
      min: parseFloat(Math.min(...values).toFixed(2)),
      max: parseFloat(Math.max(...values).toFixed(2))
    };
  }
});

return [{
  json: {
    email: parsed.email,
    name: parsed.name,
    filename: parsed.filename,
    rowCount: parsed.rowCount,
    headers: parsed.headers,
    stats,
    timestamp: new Date().toISOString()
  }
}];
